@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application collects cookies to improve your experience.
    We respect your privacy and handle all data in accordance with applicable regulations.
</p>

@if (hasConsent)
{
    <div class="alert alert-success mt-3">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning mt-3">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

@code {
    private bool hasConsent;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            hasConsent = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

